class RangeModule {
public:
    vector<pair<int, int>> ranges;

    RangeModule() {

    }

    void addRange(int left, int right) {
        int n = ranges.size();
        if (n == 0 || ranges[n-1].second < left) {
            ranges.push_back({left, right});
        } else if (ranges[n-1].first < right) {
            ranges[n-1].second = max(ranges[n-1].second, right);
        }
        for (int i = n-2; i >= 0; --i) {
            if (ranges[i].second >= left && ranges[i].first < right) {
                ranges[i].second = max(ranges[i].second, ranges[n-1].second);
                ranges.pop_back();
                n--;
            }
        }
    }

    bool queryRange(int left, int right) {
        int n = ranges.size();
        for (int i = 0; i < n; ++i) {
            if (ranges[i].first < right && ranges[i].second >= left) {
                return true;
            }
        }
        return false;
    }

    void removeRange(int left, int right) {
        int n = ranges.size();
        for (int i = 0; i < n; ++i) {
            if (ranges[i].first < right && ranges[i].second >= left) {
                if (i > 0 && ranges[i-1].second >= left) {
                    ranges[i-1].second = max(ranges[i-1].second, ranges[i].second);
                }
                if (i + 1 < n && ranges[i+1].first <= right) {
                    ranges[i].second = min(ranges[i].second, ranges[i+1].first);
                }
                ranges.erase(ranges.begin() + i);
                --i;
                --n;
            }
        }
    }
};
```

